import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { 
  FiShield, 
  FiArrowLeft, 
  FiUsers, 
  FiCalendar, 
  FiDollarSign,
  FiTrendingUp,
  FiUserPlus,
  FiSettings,
  FiLogOut,
  FiBarChart,
  FiCheckCircle,
  FiClock,
  FiXCircle,
  FiEye,
  FiPackage,
  FiGift,
  FiX
} from 'react-icons/fi';
import { MdVisibility, MdReply, MdViewList, MdViewModule, MdSearch, MdFilterList } from 'react-icons/md';
import { useAuth } from '../context/AuthContext';
import { Booking, Employee, ContactQuery } from '../types';
import { apiService } from '../services/api';
import { API_ENDPOINTS, API_BASE_URL } from '../config/api';
import { useQuery } from 'react-query';
import toast from 'react-hot-toast';
import axios from 'axios';
import { getApiUrl } from '../config/api';
import Modal from '../components/Modal'; // Added Modal import

const AdminDashboard: React.FC = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState<'overview' | 'bookings' | 'employees' | 'queries' | 'services' | 'offers'>('overview');
  const [bookingsTab, setBookingsTab] = useState<'all' | 'pending' | 'accepted' | 'completed'>('all');
  const [selectedBooking, setSelectedBooking] = useState<Booking | null>(null);
  const [showBookingModal, setShowBookingModal] = useState(false);
  const [assignTechId, setAssignTechId] = useState<string>('');
  const [assignLoading, setAssignLoading] = useState(false);
  const [verifyLoading, setVerifyLoading] = useState(false);
  const [queryViewMode, setQueryViewMode] = useState<'table' | 'card'>('table');
  const [showQueryModal, setShowQueryModal] = useState(false);
  const [showRespondModal, setShowRespondModal] = useState(false);
  const [selectedQuery, setSelectedQuery] = useState<any>(null);
  const [respondText, setRespondText] = useState('');
  const [respondLoading, setRespondLoading] = useState(false);
  const [querySearch, setQuerySearch] = useState('');
  const [showFilterDropdown, setShowFilterDropdown] = useState(false);
  const [statusFilter, setStatusFilter] = useState('all');
  const [dateFilter, setDateFilter] = useState('all');

  // Add state for service details modal
  const [selectedService, setSelectedService] = useState<any>(null);
  const [serviceDetailsModalOpen, setServiceDetailsModalOpen] = useState(false);
  const [serviceDetailsData, setServiceDetailsData] = useState<any>(null);
  const [serviceDetailsLoading, setServiceDetailsLoading] = useState(false);

  // Add state for offer details modal
  const [selectedOffer, setSelectedOffer] = useState<any>(null);
  const [offerDetailsModalOpen, setOfferDetailsModalOpen] = useState(false);

  // Add state for service editing
  const [editingServiceTypes, setEditingServiceTypes] = useState<any[]>([]);
  const [originalServiceTypes, setOriginalServiceTypes] = useState<any[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);

  // No strict user.id or user.name checks here; just rely on ProtectedRoute
  const sessionId = localStorage.getItem('sessionId');
  // Fetch dashboard data
  const { data: bookingsData, isLoading: bookingsLoading } = useQuery(
    'admin-bookings',
    () => apiService.get<{ bookings: Booking[] }>(`${API_ENDPOINTS.ADMIN_ORDERS}?session_id=${sessionId}`),
    {
      retry: 1,
      onError: (error) => {
        toast.error('Failed to load bookings');
      }
    }
  );

  const { data: employeesData, isLoading: employeesLoading } = useQuery(
    'employees',
    () => apiService.get<{ employees: Employee[] }>(`${API_ENDPOINTS.GET_TECHNICIANS}?session_id=${sessionId}`),
    {
      retry: 1,
      onError: (error) => {
        toast.error('Failed to load employees');
      }
    }
  );

  const { data: queriesData, isLoading: queriesLoading } = useQuery(
    'contact-queries',
    () => apiService.get<{ queries: ContactQuery[] }>(`${API_ENDPOINTS.ADMIN_CONTACT_QUERIES}?session_id=${sessionId}`),
    {
      retry: 1,
      onError: (error) => {
        toast.error('Failed to load contact queries');
      }
    }
  );

  const { data: servicesData, isLoading: servicesLoading } = useQuery(
    'services',
    () => apiService.get<any>(`${API_ENDPOINTS.FETCH_SERVICES}?session_id=${sessionId}`),
    {
      retry: 1,
      onError: (error) => {
        toast.error('Failed to load services');
      }
    }
  );

  const { data: offersData, isLoading: offersLoading } = useQuery(
    'offers',
    () => apiService.get<any>(`${API_ENDPOINTS.FETCH_OFFERS}?session_id=${sessionId}`),
    {
      retry: 1,
      onError: (error) => {
        toast.error('Failed to load offers');
      }
    }
  );

  // Combine bookings arrays from API response (pending, completed, accepted)
  const bookingsDataAny = bookingsData as any;
  const bookings = [
    ...(bookingsDataAny?.orders?.pending || []),
    ...(bookingsDataAny?.orders?.completed || []),
    ...(bookingsDataAny?.orders?.accepted || [])
  ];

  // Sort bookings by service_date descending (latest first)
  const sortedBookings = bookings.sort((a, b) => new Date(b.service_date).getTime() - new Date(a.service_date).getTime());

  // Employees: use data array from API response and map to UI model
  const employeesDataAny = employeesData as any;
  const employees = (employeesDataAny?.data || []).map((emp: any) => ({
    id: emp.technician_id,
    name: emp.employee_name,
    email: emp.email,
    mobile: emp.phone_number,
    serviceType: emp.service_type,
    address: emp.address,
    idProof: emp.id_proof,
  }));

  // Combine queries arrays if nested (adjust as needed)
  const queriesDataAny = queriesData as any;
  const queries = queriesDataAny?.queries || queriesDataAny?.data?.queries || [];

  // Services: use data array from API response
  const servicesDataAny = servicesData as any;
  const services = servicesDataAny?.services || servicesDataAny?.data?.services || [];

  // Offers: use data array from API response
  const offersDataAny = offersData as any;
  const offers = offersDataAny?.offers || offersDataAny?.data?.offers || [];

  // Add explicit types to map/filter/reduce parameters
  const totalBookings = bookings.length;
  const pendingBookings = bookings.filter((b: Booking) => (b.booking_status && b.booking_status.toLowerCase() === 'pending')).length;
  const completedBookings = bookings.filter((b: Booking) => b.status === 'completed').length;
  const totalRevenue = bookings.reduce((sum: number, b: Booking) => sum + b.total_amount, 0);
  const pendingQueries = queries.filter((q: ContactQuery) => q.status === 'pending').length;

  const handleLogout = () => {
    logout();
    navigate('/');
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'completed':
        return 'bg-green-100 text-green-800';
      case 'accepted':
        return 'bg-blue-100 text-blue-800';
      case 'pending':
        return 'bg-yellow-100 text-yellow-800';
      case 'cancelled':
        return 'bg-red-100 text-red-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  const formatDate = (dateString: string) => {
    const date = new Date(dateString);
    return date.toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'short',
      day: 'numeric'
    });
  };

  const statsCards = [
    {
      title: 'Total Bookings',
      value: totalBookings,
      icon: FiCalendar,
      color: 'bg-blue-500',
      change: '+12%'
    },
    {
      title: 'Pending Bookings',
      value: pendingBookings,
      icon: FiClock,
      color: 'bg-yellow-500',
      change: '+5%'
    },
    {
      title: 'Total Revenue',
      value: `₹${totalRevenue.toLocaleString()}`,
      icon: FiDollarSign,
      color: 'bg-green-500',
      change: '+18%'
    },
    {
      title: 'Active Employees',
      value: employees.length,
      icon: FiUsers,
      color: 'bg-purple-500',
      change: '+2'
    }
  ];

  function handleResetPassword(technicianId: string) {
    if (window.confirm('Are you sure you want to reset the password for this employee? The new password will be set to "12345".')) {
      const sessionId = localStorage.getItem('sessionId');
      axios.post(`${process.env.REACT_APP_API_BASE_URL || ''}reset_password.php`, {
        technician_id: technicianId,
        newpassword: '12345',
      }, {
        headers: {
          'Content-Type': 'application/json',
          'Session-ID': sessionId || '',
        },
      })
        .then((response) => {
          alert(response.data.message || 'Password reset successful!');
        })
        .catch(() => {
          alert('Failed to reset password. Please try again.');
        });
    }
  }

  // Filter queries based on search and filters
  const filteredQueries = queries.filter((query: any) => {
    const search = querySearch.toLowerCase();
    const matchesSearch = (
      (query.customer_name || `${query.first_name} ${query.last_name}`)?.toLowerCase().includes(search) ||
      (query.email || '').toLowerCase().includes(search) ||
      (query.subject || '').toLowerCase().includes(search) ||
      (query.message || '').toLowerCase().includes(search)
    );

    const matchesStatus = statusFilter === 'all' || query.status === statusFilter;

    const matchesDate = (() => {
      if (dateFilter === 'all') return true;
      const queryDate = new Date(query.created_at);
      const now = new Date();
      if (dateFilter === '7days') {
        const sevenDaysAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
        return queryDate >= sevenDaysAgo;
      }
      if (dateFilter === '30days') {
        const thirtyDaysAgo = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);
        return queryDate >= thirtyDaysAgo;
      }
      return true;
    })();

    return matchesSearch && matchesStatus && matchesDate;
  });

  // Add function to fetch service details
  const fetchServiceDetails = async (serviceName: string) => {
    setServiceDetailsLoading(true);
    try {
      const response = await apiService.get<any>(`${API_ENDPOINTS.GET_SERVICE_DETAILS}?service_name=${serviceName}&session_id=${sessionId}`);
      setServiceDetailsData(response.data);
    } catch (error) {
      toast.error('Failed to load service details');
    } finally {
      setServiceDetailsLoading(false);
    }
  };

  // Update the handleViewServiceDetails function to open editing interface
  const handleViewServiceDetails = async (service: any) => {
    setSelectedService(service);
    setServiceDetailsModalOpen(true);
    setServiceDetailsLoading(true);

    try {
      const response = await apiService.get<any>(`${API_ENDPOINTS.GET_SERVICE_DETAILS}?service_name=${service.service_name}&session_id=${sessionId}`);

      if (response.data && response.data.length > 0) {
        setEditingServiceTypes(response.data);
        setOriginalServiceTypes(JSON.parse(JSON.stringify(response.data))); // Deep copy
      } else {
        // If no data found, add an empty service type
        setEditingServiceTypes([{
          service_type_name: '',
          service_type_id: null,
          pricing_fields: [{ room_size: '', price: '', pricing_field_id: null }]
        }]);
        setOriginalServiceTypes([]);
      }
    } catch (error) {
      toast.error('Failed to load service details');
      // Add an empty service type as fallback
      setEditingServiceTypes([{
        service_type_name: '',
        service_type_id: null,
        pricing_fields: [{ room_size: '', price: '', pricing_field_id: null }]
      }]);
      setOriginalServiceTypes([]);
    } finally {
      setServiceDetailsLoading(false);
    }
  };

  // Add function to handle view offer details click
  const handleViewOfferDetails = (offer: any) => {
    setSelectedOffer(offer);
    setOfferDetailsModalOpen(true);
  };

  // Add function to delete offer
  const handleDeleteOffer = async (offerId: string) => {
    if (window.confirm('Are you sure you want to delete this offer?')) {
      try {
        await apiService.get<any>(`delete_offers.php?offer_id=${offerId}&session_id=${sessionId}`);
        toast.success('Offer deleted successfully');
        // Refresh the offers data
        window.location.reload();
      } catch (error) {
        toast.error('Failed to delete offer');
      }
    }
  };

  // Add function to update service type name
  const updateServiceTypeName = (index: number, value: string) => {
    const updated = [...editingServiceTypes];
    updated[index].service_type_name = value;
    setEditingServiceTypes(updated);
  };

  // Add function to update pricing field
  const updatePricingField = (serviceTypeIndex: number, fieldIndex: number, field: string, value: string) => {
    const updated = [...editingServiceTypes];
    updated[serviceTypeIndex].pricing_fields[fieldIndex][field] = value;
    setEditingServiceTypes(updated);
  };

  // Add function to add pricing field
  const addPricingField = (serviceTypeIndex: number) => {
    const updated = [...editingServiceTypes];
    updated[serviceTypeIndex].pricing_fields.push({
      room_size: '',
      price: '',
      pricing_field_id: null
    });
    setEditingServiceTypes(updated);
  };

  // Add function to remove pricing field
  const removePricingField = (serviceTypeIndex: number, fieldIndex: number) => {
    const updated = [...editingServiceTypes];
    updated[serviceTypeIndex].pricing_fields.splice(fieldIndex, 1);
    if (updated[serviceTypeIndex].pricing_fields.length === 0) {
      updated[serviceTypeIndex].pricing_fields.push({
        room_size: '',
        price: '',
        pricing_field_id: null
      });
    }
    setEditingServiceTypes(updated);
  };

  // Add function to add service type
  const addServiceType = () => {
    setEditingServiceTypes([...editingServiceTypes, {
      service_type_name: '',
      service_type_id: null,
      pricing_fields: [{ room_size: '', price: '', pricing_field_id: null }]
    }]);
  };

  // Add function to remove service type
  const removeServiceType = (index: number) => {
    if (editingServiceTypes.length > 1) {
      const updated = editingServiceTypes.filter((_, i) => i !== index);
      setEditingServiceTypes(updated);
    }
  };

  // Add function to submit changes
  const submitServiceChanges = async () => {
    // Validate input
    for (const serviceType of editingServiceTypes) {
      if (!serviceType.service_type_name.trim()) {
        toast.error('Service type name cannot be empty');
        return;
      }

      for (const field of serviceType.pricing_fields) {
        if (!field.room_size.trim()) {
          toast.error('Room size cannot be empty');
          return;
        }
        if (!field.price.trim()) {
          toast.error('Price cannot be empty');
          return;
        }
        if (isNaN(Number(field.price))) {
          toast.error('Price must be a valid number');
          return;
        }
      }
    }

    setIsSubmitting(true);

    try {
      // Handle updates (additions, modifications, deletions)
      for (let i = 0; i < editingServiceTypes.length; i++) {
        const serviceType = editingServiceTypes[i];

        // If this is a new service type (no ID), add it
        if (!serviceType.service_type_id) {
          const requestBody = {
            service_name: selectedService.service_name,
            service_type_name: serviceType.service_type_name,
            pricing: serviceType.pricing_fields.map((field: any) => ({
              room_size: field.room_size,
              price: field.price
            }))
          };

          await apiService.post(API_ENDPOINTS.ADD_SERVICE_TYPE, requestBody);
          continue;
        }

        // Find the original service type to compare
        const originalType = originalServiceTypes.find((original: any) => 
          original.service_type_id === serviceType.service_type_id
        );

        if (originalType) {
          // Handle service type name update if changed
          if (originalType.service_type_name !== serviceType.service_type_name) {
            await apiService.post(API_ENDPOINTS.UPDATE_SERVICE_TYPE, {
              service_type_id: serviceType.service_type_id,
              service_type_name: serviceType.service_type_name
            });
          }

          // Handle pricing fields updates
          // This is a simplified version - in a real implementation you'd need more complex logic
          // to handle individual field additions/deletions
        }
      }

      toast.success('Service updated successfully');
      setServiceDetailsModalOpen(false);
      // Refresh the services data
      window.location.reload();
    } catch (error) {
      toast.error('Failed to update service');
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Header */}
      <div className="bg-white shadow-sm border-b">
        <div className="flex items-center justify-between px-6 py-4">
          <div className="flex items-center space-x-3">
            <button
              onClick={() => navigate('/')}
              className="text-gray-600 hover:text-gray-800"
            >
              <FiArrowLeft size={20} />
            </button>
            <div className="flex items-center space-x-2">
              <div className="w-8 h-8 bg-teal-500 rounded-lg flex items-center justify-center">
                <FiShield className="text-white" size={16} />
              </div>
              <div>
                <h1 className="text-lg font-bold text-gray-900">NPC Admin</h1>
                <p className="text-xs text-gray-500">Administration Panel</p>
              </div>
            </div>
          </div>
          <div className="flex items-center space-x-4">
            <span className="text-sm text-gray-600">Welcome, {user?.name || 'Admin'}</span>
            <button
              onClick={handleLogout}
              className="text-gray-600 hover:text-gray-800"
              title="Logout"
            >
              <FiLogOut size={18} />
            </button>
          </div>
        </div>
      </div>

      <div className="flex">
        {/* Sidebar Navigation */}
        <div className="w-64 bg-white shadow-sm min-h-screen">
          <div className="p-6">
            <h2 className="text-lg font-semibold text-gray-900 mb-6">Admin Dashboard</h2>
            <nav className="space-y-2">
              {[
                { id: 'overview', label: 'Overview', icon: FiBarChart },
                { id: 'bookings', label: 'Bookings', icon: FiCalendar },
                { id: 'employees', label: 'Employees', icon: FiUsers },
                { id: 'queries', label: 'Contact Queries', icon: FiSettings },
                { id: 'services', label: 'Service Details', icon: FiPackage },
                { id: 'offers', label: 'Offer Details', icon: FiGift }
              ].map((tab) => (
                <button
                  key={tab.id}
                  onClick={() => setActiveTab(tab.id as any)}
                  className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg text-left transition-colors ${
                    activeTab === tab.id
                      ? 'bg-teal-50 text-teal-700 border-r-2 border-teal-500'
                      : 'text-gray-600 hover:bg-gray-50 hover:text-gray-900'
                  }`}
                >
                  <tab.icon className="w-5 h-5" />
                  <span className="font-medium">{tab.label}</span>
                </button>
              ))}
            </nav>
          </div>
        </div>

        {/* Main Content */}
        <div className="flex-1 p-6">
          {/* Overview Tab - Show Stats Cards */}
          {activeTab === 'overview' && (
            <>
              <div className="mb-8">
                <h1 className="text-2xl font-bold text-gray-900 mb-2">Overview</h1>
                <p className="text-gray-600">Manage your business operations</p>
              </div>

              {/* Statistics Cards */}
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
                {statsCards.map((stat, index) => (
                  <motion.div
                    key={stat.title}
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ duration: 0.3, delay: index * 0.1 }}
                    className="bg-white rounded-lg shadow-sm p-6"
                  >
                    <div className="flex items-center justify-between">
                      <div>
                        <p className="text-sm font-medium text-gray-600">{stat.title}</p>
                        <p className="text-2xl font-bold text-gray-900">{stat.value}</p>
                      </div>
                      <div className={`w-12 h-12 ${stat.color} rounded-lg flex items-center justify-center`}>
                        <stat.icon className="w-6 h-6 text-white" />
                      </div>
                    </div>
                  </motion.div>
                ))}
              </div>

              {/* Overview Content */}
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                {/* Recent Bookings */}
                <div className="bg-white rounded-lg shadow-sm p-6">
                  <h3 className="text-lg font-semibold text-gray-900 mb-4">Recent Bookings</h3>
                  {bookingsLoading ? (
                    <div className="flex justify-center py-8">
                      <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-teal-600"></div>
                    </div>
                  ) : bookings.length === 0 ? (
                    <p className="text-gray-500 text-center py-8">No bookings found</p>
                  ) : (
                    <div className="space-y-3">
                      {bookings.slice(0, 5).map((booking: Booking) => (
                        <div key={booking.booking_id} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                          <div>
                            <p className="font-medium text-gray-900">{booking.service_name}</p>
                            <p className="text-sm text-gray-600">{formatDate(booking.service_date)}</p>
                          </div>
                          <span className={`px-2 py-1 rounded-full text-xs font-medium ${getStatusColor(String(booking.status || ''))}`}>
                            {booking.status}
                          </span>
                        </div>
                      ))}
                    </div>
                  )}
                </div>

                {/* Pending Queries */}
                <div className="bg-white rounded-lg shadow-sm p-6">
                  <h3 className="text-lg font-semibold text-gray-900 mb-4">Pending Contact Queries</h3>
                  {queriesLoading ? (
                    <div className="flex justify-center py-8">
                      <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-teal-600"></div>
                    </div>
                  ) : pendingQueries === 0 ? (
                    <p className="text-gray-500 text-center py-8">No pending queries</p>
                  ) : (
                    <div className="space-y-3">
                      {queries.filter((q: ContactQuery) => (q as ContactQuery).status === 'pending').slice(0, 5).map((query: ContactQuery) => (
                        <div key={query.query_id} className="p-3 bg-gray-50 rounded-lg">
                          <p className="font-medium text-gray-900">{query.subject}</p>
                          <p className="text-sm text-gray-600">{query.first_name} {query.last_name}</p>
                          <p className="text-xs text-gray-500">{formatDate(query.created_at)}</p>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              </div>
            </>
          )}

          {/* Bookings Tab */}
          {activeTab === 'bookings' && (
            <div>
              <div className="mb-6">
                <h1 className="text-2xl font-bold text-gray-900 mb-2">All Bookings</h1>
              </div>

              {/* Booking Status Filters */}
              <div className="flex flex-wrap gap-2 mb-6">
                {(['all', 'pending', 'accepted', 'completed'] as const).map((status: 'all' | 'pending' | 'accepted' | 'completed') => (
                  <button
                    key={status}
                    onClick={() => setBookingsTab(status)}
                    className={`px-4 py-2 rounded-lg font-medium transition-colors ${
                      bookingsTab === status
                        ? 'bg-teal-500 text-white'
                        : 'bg-white text-gray-700 border border-gray-300 hover:bg-gray-50'
                    }`}
                  >
                    {status.charAt(0).toUpperCase() + status.slice(1)}
                  </button>
                ))}
              </div>

              {/* Bookings Table */}
              {bookingsLoading ? (
                <div className="flex justify-center py-12">
                  <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-teal-600"></div>
                </div>
              ) : (
                <div className="bg-white rounded-lg shadow-sm overflow-hidden">
                  <div className="overflow-x-auto">
