              )}
            </div>
          </div>
        </div>
      )}

      {showQueryModal && selectedQuery && (
        <Modal onClose={() => setShowQueryModal(false)}>
          <h2 className="text-xl font-bold mb-4 text-teal-700">Query Details</h2>
          <div className="space-y-2">
            <div><b>Customer:</b> {selectedQuery.customer_name || `${selectedQuery.first_name} ${selectedQuery.last_name}`}</div>
            <div><b>Email:</b> {selectedQuery.email}</div>
            <div><b>Phone:</b> {selectedQuery.phone}</div>
            <div><b>Subject:</b> {selectedQuery.subject}</div>
            <div><b>Date:</b> {formatDate(selectedQuery.created_at)}</div>
            <div><b>Message:</b> <div className="bg-gray-50 rounded p-2 mt-1 text-gray-700 whitespace-pre-line">{selectedQuery.message}</div></div>
            {selectedQuery.admin_response && (
              <div className="mt-2"><b>Admin Response:</b> <div className="bg-green-50 rounded p-2 mt-1 text-green-700 whitespace-pre-line">{selectedQuery.admin_response}</div></div>
            )}
            {selectedQuery.response_date_formatted && (
              <div className="text-xs text-gray-500">Responded: {selectedQuery.response_date_formatted}</div>
            )}
          </div>
          <div className="flex justify-end gap-2 mt-6">
            {selectedQuery.status === 'pending' && (
              <button 
                className="px-4 py-2 rounded bg-blue-500 text-white hover:bg-blue-600 transition"
                onClick={() => {
                  setShowQueryModal(false);
                  setShowRespondModal(true);
                }}
              >
                Reply
              </button>
            )}
            <button className="px-4 py-2 rounded bg-gray-200 text-gray-700 hover:bg-gray-300 transition" onClick={() => setShowQueryModal(false)}>Close</button>
          </div>
        </Modal>
      )}
      {showRespondModal && selectedQuery && (
        <Modal onClose={() => setShowRespondModal(false)}>
          <h2 className="text-xl font-bold mb-4 text-blue-700">Respond to Query</h2>
          <textarea value={respondText} onChange={e => setRespondText(e.target.value)} rows={5} className="w-full border border-gray-300 rounded p-2 focus:outline-none focus:ring-2 focus:ring-blue-400" placeholder="Type your response..." />
          <div className="flex justify-end gap-2 mt-4">
            <button className="px-4 py-2 rounded bg-gray-200 text-gray-700 hover:bg-gray-300 transition" onClick={() => setShowRespondModal(false)}>Cancel</button>
            <button className="px-4 py-2 rounded bg-blue-500 text-white hover:bg-blue-600 transition disabled:opacity-50" disabled={respondLoading || respondText.length < 10} onClick={async () => {
              setRespondLoading(true);
              try {
                await apiService.post('admin_contact_queries.php', {
                  query_id: selectedQuery.id,
                  response: respondText,
                  status: 'responded',
                });
                toast.success('Response submitted!');
                setShowRespondModal(false);
                setRespondText('');
                // Optionally refresh queries here
              } catch {
                toast.error('Failed to submit response.');
              } finally {
                setRespondLoading(false);
              }
            }}>Send Response</button>
          </div>
        </Modal>
      )}

      {/* Service Details Modal - Updated to Editing Interface */}
      {serviceDetailsModalOpen && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
          <div className="bg-white rounded-lg shadow-xl max-w-4xl w-full mx-4 max-h-[90vh] overflow-y-auto">
            <div className="flex items-center justify-between p-6 border-b">
              <h2 className="text-xl font-bold text-gray-900">
                Edit Service: {selectedService?.service_name}
              </h2>
              <button
                onClick={() => setServiceDetailsModalOpen(false)}
                className="text-gray-400 hover:text-gray-600"
              >
                <FiX className="w-6 h-6" />
              </button>
            </div>

            <div className="p-6">
              {serviceDetailsLoading ? (
                <div className="flex justify-center py-8">
                  <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-teal-600"></div>
                </div>
              ) : (
                <div className="space-y-6">
                  {/* Service Types and Pricing */}
                  <div>
                    <h3 className="text-lg font-semibold text-gray-900 mb-4">Service Types & Pricing</h3>
                    <div className="space-y-4">
                      {editingServiceTypes.map((serviceType, serviceTypeIndex) => (
                        <div key={serviceTypeIndex} className="border rounded-lg p-4 bg-gray-50">
                          <div className="flex items-center justify-between mb-4">
                            <input
                              type="text"
                              value={serviceType.service_type_name}
                              onChange={(e) => updateServiceTypeName(serviceTypeIndex, e.target.value)}
                              placeholder="Service Type Name"
                              className="text-lg font-medium text-gray-900 bg-white px-3 py-2 border rounded flex-1 mr-4"
                            />
                            {editingServiceTypes.length > 1 && (
                              <button
                                onClick={() => removeServiceType(serviceTypeIndex)}
                                className="text-red-600 hover:text-red-800 px-2 py-1 border border-red-600 rounded hover:bg-red-50"
                              >
                                Remove Type
                              </button>
                            )}
                          </div>

                          <div className="space-y-3">
                            <h4 className="font-medium text-gray-700">Pricing Fields:</h4>
                            {serviceType.pricing_fields.map((field: any, fieldIndex: number) => (
                              <div key={fieldIndex} className="flex items-center space-x-3">
                                <input
                                  type="text"
                                  value={field.room_size}
                                  onChange={(e) => updatePricingField(serviceTypeIndex, fieldIndex, 'room_size', e.target.value)}
                                  placeholder="Room Size"
                                  className="flex-1 bg-white px-3 py-2 border rounded"
                                />
                                <input
                                  type="number"
                                  value={field.price}
                                  onChange={(e) => updatePricingField(serviceTypeIndex, fieldIndex, 'price', e.target.value)}
                                  placeholder="Price"
                                  className="flex-1 bg-white px-3 py-2 border rounded"
                                />
                                {serviceType.pricing_fields.length > 1 && (
                                  <button
                                    onClick={() => removePricingField(serviceTypeIndex, fieldIndex)}
                                    className="text-red-600 hover:text-red-800 px-2 py-1"
                                  >
                                    Remove
                                  </button>
                                )}
                              </div>
                            ))}
                            <button
                              onClick={() => addPricingField(serviceTypeIndex)}
                              className="text-teal-600 hover:text-teal-800 px-3 py-1 border border-teal-600 rounded hover:bg-teal-50"
                            >
                              + Add Pricing Field
                            </button>
                          </div>
                        </div>
                      ))}

                      <button
                        onClick={addServiceType}
                        className="text-green-600 hover:text-green-800 px-4 py-2 border border-green-600 rounded hover:bg-green-50 flex items-center"
                      >
                        <span className="mr-2">+</span>
                        Add Another Service Type
                      </button>
                    </div>
                  </div>

                  {/* Submit Button */}
                  <div className="flex justify-end space-x-3 pt-4 border-t">
                    <button
                      onClick={() => setServiceDetailsModalOpen(false)}
                      className="px-4 py-2 bg-gray-600 text-white rounded hover:bg-gray-700 transition-colors"
                    >
                      Cancel
                    </button>
                    <button
                      onClick={submitServiceChanges}
                      disabled={isSubmitting}
                      className="px-6 py-2 bg-teal-600 text-white rounded hover:bg-teal-700 transition-colors disabled:opacity-50"
                    >
                      {isSubmitting ? 'Saving...' : 'Save Changes'}
                    </button>
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Offer Details Modal */}
      {offerDetailsModalOpen && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
          <div className="bg-white rounded-lg shadow-xl max-w-2xl w-full mx-4 max-h-[90vh] overflow-y-auto">
            <div className="flex items-center justify-between p-6 border-b">
              <h2 className="text-xl font-bold text-gray-900">
                Offer Details: {selectedOffer?.offer_name}
              </h2>
              <button
                onClick={() => setOfferDetailsModalOpen(false)}
                className="text-gray-400 hover:text-gray-600"
              >
                <FiX className="w-6 h-6" />
              </button>
            </div>

            <div className="p-6">
              <div className="space-y-6">
                {/* Offer Information */}
                <div>
                  <h3 className="text-lg font-semibold text-gray-900 mb-4">Offer Information</h3>
                  <div className="bg-gray-50 rounded-lg p-4 space-y-4">
                    <div className="grid grid-cols-2 gap-4">
                      <div>
                        <span className="text-sm font-medium text-gray-500">Offer Name:</span>
                        <p className="text-gray-900 font-medium">{selectedOffer?.offer_name}</p>
                      </div>
                      <div>
                        <span className="text-sm font-medium text-gray-500">Coupon Code:</span>
                        <p className="text-gray-900 font-mono bg-white px-2 py-1 rounded border">{selectedOffer?.coupon_number}</p>
                      </div>
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                      <div>
                        <span className="text-sm font-medium text-gray-500">Discount:</span>
                        <p className="text-green-600 font-bold text-lg">{selectedOffer?.offer_percentage}% off</p>
                      </div>
                      <div>
                        <span className="text-sm font-medium text-gray-500">Status:</span>
                        <span className={`px-2 py-1 rounded-full text-xs font-medium ${
                          selectedOffer?.status === 'active' ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'
                        }`}>
                          {selectedOffer?.status}
                        </span>
                      </div>
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                      <div>
                        <span className="text-sm font-medium text-gray-500">Start Date:</span>
                        <p className="text-gray-900">{formatDate(selectedOffer?.offer_starts_on)}</p>
                      </div>
                      <div>
                        <span className="text-sm font-medium text-gray-500">End Date:</span>
                        <p className="text-gray-900">{formatDate(selectedOffer?.expires_on)}</p>
                      </div>
                    </div>
                  </div>
                </div>

                {/* Offer Banner */}
                {selectedOffer?.offer_banner_location && (
                  <div>
                    <h3 className="text-lg font-semibold text-gray-900 mb-4">Offer Banner</h3>
                    <div className="bg-gray-50 rounded-lg p-4">
                      <img 
                        src={`${API_BASE_URL}offer-banner/${selectedOffer.offer_banner_location}`}
                        alt="Offer Banner"
                        className="w-full h-32 object-cover rounded"
                        onError={(e) => {
                          e.currentTarget.style.display = 'none';
                        }}
                      />
                    </div>
                  </div>
                )}

                {/* Actions */}
                <div>
                  <h3 className="text-lg font-semibold text-gray-900 mb-4">Actions</h3>
                  <div className="flex space-x-3">
                    <button
                      onClick={() => handleDeleteOffer(selectedOffer?.offer_id)}
                      className="px-4 py-2 bg-red-600 text-white rounded hover:bg-red-700 transition-colors"
                    >
                      Delete Offer
                    </button>
                    <button
                      onClick={() => setOfferDetailsModalOpen(false)}
                      className="px-4 py-2 bg-gray-600 text-white rounded hover:bg-gray-700 transition-colors"
                    >
                      Close
                    </button>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;
